// UpdateExpenseRequest defines model for UpdateExpenseRequest.
type UpdateExpenseRequest struct {
	AmountCents *int64              `json:"amount_cents,omitempty"`
	CategoryId  *openapi_types.UUID `json:"category_id,omitempty"`
	Description *string             `json:"description,omitempty"`

	// IncurredAt When the expense was incurred (independent of when it was recorded).
	// Defaults to the creation time if omitted on create, then immutable
	// unless explicitly set here.
	IncurredAt *time.Time `json:"incurred_at,omitempty"`

	// Mode Must be supplied together with `splits`. When both are present, the server
	// re-resolves per-user shares. When neither is present, existing splits are
	// rescaled proportionally if `amount_cents` changes.
	Mode *SplitMode `json:"mode,omitempty"`

	// Notes Optional free-form notes about the expense.
	Notes *string `json:"notes,omitempty"`

	// PayerId New payer; must be a current group member.
	PayerId *openapi_types.UUID `json:"payer_id,omitempty"`

	// Splits Must be supplied together with `mode`.
	Splits *[]SplitInput `json:"splits,omitempty"`
}

